def module_name_from_path(rel_path):
    parts = rel_path.replace(os.sep, '.').replace('.py', '').split('.')
    if parts[-1] == '__init__':
        parts = parts[:-1]
    return '.'.join(parts)

def package_of(module_name):
    parts = module_name.split('.')
    return '.'.join(parts[:-1])

def resolve_relative(level, current_module, is_init):
    pkg = current_module if is_init else package_of(current_module)
    parts = pkg.split('.')
    up = level - 1
    if up >= len(parts):
        return ''
    return '.'.join(parts[:-up] if up else parts)

def resolve_base(base_node, imports, current_module, is_init):
    if isinstance(base_node, ast.Name):
        name = base_node.id
        info = imports.get(name)
        if isinstance(info, tuple):
            mod, real_name, level = info
            if level:
                resolved = resolve_relative(level, current_module, is_init)
                module = resolved + (('.' + mod) if mod else '')
                return real_name, module
            return real_name, mod
        elif isinstance(info, str):
            return name, info
        else:
            return name, current_module
    elif isinstance(base_node, ast.Attribute):
        parts = []
        node = base_node
        while isinstance(node, ast.Attribute):
            parts.append(node.attr)
            node = node.value
        if isinstance(node, ast.Name):
            parts.append(node.id)
            parts.reverse()
            class_name = parts[-1]
            prefix = '.'.join(parts[:-1])
